  Selectable<int> kanji_dictionary_find_kanji_bank_entries_drift(
    String? indexesToInclude,
    List<String> kanjis,
  ) {
    var $arrayStartIndex = 2;
    final expandedkanjis = $expandVar($arrayStartIndex, kanjis.length);
    $arrayStartIndex += kanjis.length;
    return customSelect(
      'WITH IndexesToInclude (index_id) AS (SELECT value FROM json_each(?1)) SELECT KBV3T.id AS id FROM kanji_table AS KDT JOIN kanji_bank_v3_table AS KBV3T ON KBV3T.kanji_id = KDT.id JOIN index_table AS IT ON KBV3T.index_id = IT.id WHERE KDT.kanji IN ($expandedkanjis) AND((?1 IS NOT NULL AND IT.id IN (SELECT index_id FROM IndexesToInclude))OR(?1 IS NULL AND IT.enabled = 1))',
      variables: [
        Variable<String>(indexesToInclude),
        for (var $ in kanjis) Variable<String>($),
      ],
      readsFrom: {kanjiBankV3Table, kanjiTable, indexTable},
    ).map((QueryRow row) => row.read<int>('id'));
  }

  Selectable<KanjiDictionaryFindKanjiDetailsDriftResult>
  kanji_dictionary_find_kanji_details_drift(
    String? indexesToInclude,
    List<int> ids,
  ) {
    var $arrayStartIndex = 2;
    final expandedids = $expandVar($arrayStartIndex, ids.length);
    $arrayStartIndex += ids.length;
    return customSelect(
      'WITH IndexesToInclude (index_id) AS (SELECT value FROM json_each(?1)), ActiveIndexes (id) AS (SELECT id FROM index_table WHERE(?1 IS NOT NULL AND id IN (SELECT index_id FROM IndexesToInclude))OR(?1 IS NULL AND enabled = 1)) SELECT k.*, (SELECT json_group_array(json_object(\'id\', km.id, \'kanji\', km.kanji, \'indexEntry\', km.indexEntry, \'type\', km.type, \'freqValue\',(km.freq_value), \'freqDisplayValue\', km.freq_display_value)) FROM kanji_meta_bank_v3_entry_view AS km JOIN ActiveIndexes ON km.index_id = ActiveIndexes.id WHERE km.kanji = k.kanji) AS kanjiMetaBankV3Entries FROM kanji_bank_v3_entry_view AS k LEFT JOIN index_table AS it ON k.indexId = it.id WHERE k.id IN ($expandedids) ORDER BY it.current_sorting_order ASC, k.kanji ASC',
      variables: [
        Variable<String>(indexesToInclude),
        for (var $ in ids) Variable<int>($),
      ],
      readsFrom: {
        indexTable,
        kanjiMetaBankV3Table,
        kanjiMetaBankV3TypeTable,
        kanjiTable,
        kanjiBankV3Table,
        kanjiBankV3XOnyomiReadingTable,
        readingTable,
        kanjiBankV3XKunyomiReadingTable,
        kanjiBankV3XTagBankV3Table,
        tagBankV3Table,
        kanjiBankV3XDefinitionTable,
        definitionTable,
        kanjiBankV3StatsTable,
      },
    ).map(
      (QueryRow row) => KanjiDictionaryFindKanjiDetailsDriftResult(
        id: row.read<int>('id'),
        indexEntry: row.read<String>('indexEntry'),
        indexId: row.read<int>('indexId'),
        kanji: row.read<String>('kanji'),
        onyomis: row.read<String>('onyomis'),
        kunyomis: row.read<String>('kunyomis'),
        tags: row.read<String>('tags'),
        definitions: row.read<String>('definitions'),
        stats: row.read<String>('stats'),
        kanjiMetaBankV3Entries: row.read<String>('kanjiMetaBankV3Entries'),
      ),
    );
  }

  Selectable<DictionarySearchDriftFindTermBankEntriesResult>
  dictionary_search_drift_find_term_bank_entries(
    String searchInputs,
    String? indexesToInclude,
    int useGlob,
    int normalizedSearch,
    String? filterTerm,
    String? filterReading,
    String? filterDefinition,
    int limit,
    int offset,
  ) {
    return customSelect(
      'WITH SearchTerms (input_index, term, should_prefix, allowed_rules, allowed_tags, fts_query) AS (SELECT "key" AS input_index, CAST(json_extract(value, \'\$[0]\') AS TEXT), CAST(json_extract(value, \'\$[1]\') AS INTEGER), CAST(json_extract(value, \'\$[3]\') AS TEXT), CAST(json_extract(value, \'\$[4]\') AS TEXT), CASE WHEN CAST(json_extract(value, \'\$[2]\') AS INTEGER) = 1 THEN \'^\' ELSE \'\' END || \'"\' || "REPLACE"(CAST(json_extract(value, \'\$[0]\') AS TEXT), \'"\', \'""\') || \'"\' || CASE WHEN CAST(json_extract(value, \'\$[1]\') AS INTEGER) = 1 THEN \' *\' ELSE \'\' END FROM json_each(?1)), IndexesToInclude (index_id) AS (SELECT value FROM json_each(?2)WHERE value IS NOT NULL), ActiveIndexes (id, current_sorting_order, enabled, frequency_mode) AS (SELECT id, current_sorting_order, enabled, frequency_mode FROM index_table WHERE(?2 IS NOT NULL AND id IN (SELECT index_id FROM IndexesToInclude))OR(?2 IS NULL AND enabled = 1)), SearchResults AS (SELECT SearchTerms.input_index, SearchTerms.term AS search_term, SearchTerms.should_prefix, SearchTerms.allowed_rules, SearchTerms.allowed_tags, SearchTerms.fts_query, T.id AS source_id, 1 AS data_type_id, T.term AS text_data, fts_terms.rank FROM SearchTerms JOIN fts_terms ON fts_terms.term MATCH SearchTerms.fts_query JOIN term_table AS T ON fts_terms."rowid" = T.id WHERE ?3 = 0 AND ?4 = 0 UNION ALL SELECT SearchTerms.input_index, SearchTerms.term AS search_term, SearchTerms.should_prefix, SearchTerms.allowed_rules, SearchTerms.allowed_tags, SearchTerms.fts_query, T.id AS source_id, 3 AS data_type_id, COALESCE(T.term_normalized, T.term) AS text_data, fts_terms.rank FROM SearchTerms JOIN fts_terms ON fts_terms MATCH SearchTerms.fts_query JOIN term_table AS T ON fts_terms."rowid" = T.id WHERE ?3 = 0 AND ?4 = 1 UNION ALL SELECT SearchTerms.input_index, SearchTerms.term AS search_term, SearchTerms.should_prefix, SearchTerms.allowed_rules, SearchTerms.allowed_tags, SearchTerms.fts_query, T.id AS source_id, 2 AS data_type_id, T.term AS text_data, fts_tokens.rank FROM SearchTerms JOIN fts_tokens ON fts_tokens.tokens MATCH SearchTerms.fts_query JOIN term_table AS T ON fts_tokens."rowid" = T.id WHERE ?3 = 0 AND ?4 = 0 UNION ALL SELECT SearchTerms.input_index, SearchTerms.term AS search_term, SearchTerms.should_prefix, SearchTerms.allowed_rules, SearchTerms.allowed_tags, SearchTerms.fts_query, T.id AS source_id, 4 AS data_type_id, COALESCE(T.term_normalized, T.term) AS text_data, fts_tokens.rank FROM SearchTerms JOIN fts_tokens ON fts_tokens MATCH SearchTerms.fts_query JOIN term_table AS T ON fts_tokens."rowid" = T.id WHERE ?3 = 0 AND ?4 = 1 UNION ALL SELECT SearchTerms.input_index, SearchTerms.term AS search_term, SearchTerms.should_prefix, SearchTerms.allowed_rules, SearchTerms.allowed_tags, SearchTerms.fts_query, R.id AS source_id, 5 AS data_type_id, R.reading AS text_data, fts_readings.rank FROM SearchTerms JOIN fts_readings ON fts_readings.reading MATCH SearchTerms.fts_query JOIN reading_table AS R ON fts_readings."rowid" = R.id WHERE ?3 = 0 AND ?4 = 0 UNION ALL SELECT SearchTerms.input_index, SearchTerms.term AS search_term, SearchTerms.should_prefix, SearchTerms.allowed_rules, SearchTerms.allowed_tags, SearchTerms.fts_query, R.id AS source_id, 6 AS data_type_id, COALESCE(R.reading_normalized, R.reading) AS text_data, fts_readings.rank FROM SearchTerms JOIN fts_readings ON fts_readings MATCH SearchTerms.fts_query JOIN reading_table AS R ON fts_readings."rowid" = R.id WHERE ?3 = 0 AND ?4 = 1 UNION ALL SELECT SearchTerms.input_index, SearchTerms.term AS search_term, SearchTerms.should_prefix, SearchTerms.allowed_rules, SearchTerms.allowed_tags, SearchTerms.fts_query, fts_definitions."rowid" AS source_id, 7 AS data_type_id, fts_definitions.definition AS text_data, fts_definitions.rank FROM SearchTerms JOIN fts_definitions ON fts_definitions.definition MATCH SearchTerms.fts_query WHERE ?3 = 0 AND ?4 = 0 UNION ALL SELECT SearchTerms.input_index, SearchTerms.term AS search_term, SearchTerms.should_prefix, SearchTerms.allowed_rules, SearchTerms.allowed_tags, SearchTerms.fts_query, T.id AS source_id,(CASE WHEN ?4 = 0 THEN 1 ELSE 3 END)AS data_type_id,(CASE WHEN ?4 = 0 THEN T.term ELSE COALESCE(T.term_normalized, T.term) END)AS text_data, 0 AS rank FROM SearchTerms,term_table AS T WHERE ?3 = 1 AND(CASE WHEN ?4 = 0 THEN T.term ELSE COALESCE(T.term_normalized, T.term) END)GLOB SearchTerms.term UNION ALL SELECT SearchTerms.input_index, SearchTerms.term AS search_term, SearchTerms.should_prefix, SearchTerms.allowed_rules, SearchTerms.allowed_tags, SearchTerms.fts_query, R.id AS source_id,(CASE WHEN ?4 = 0 THEN 5 ELSE 6 END)AS data_type_id,(CASE WHEN ?4 = 0 THEN R.reading ELSE COALESCE(R.reading_normalized, R.reading) END)AS text_data, 0 AS rank FROM SearchTerms,reading_table AS R WHERE ?3 = 1 AND(CASE WHEN ?4 = 0 THEN R.reading ELSE COALESCE(R.reading_normalized, R.reading) END)GLOB SearchTerms.term UNION ALL SELECT SearchTerms.input_index, SearchTerms.term AS search_term, SearchTerms.should_prefix, SearchTerms.allowed_rules, SearchTerms.allowed_tags, SearchTerms.fts_query, D.id AS source_id, 7 AS data_type_id, D.definition AS text_data, 0 AS rank FROM SearchTerms,definition_table AS D WHERE ?3 = 1 AND D.definition GLOB SearchTerms.term), SearchResultMatchesClassified AS (SELECT SearchResults.*, CASE WHEN text_data = search_term THEN 1 WHEN text_data LIKE search_term || \'%\' THEN 2 ELSE 3 END AS match_type FROM SearchResults), SearchResultsDeduplicated AS (SELECT * FROM (SELECT SearchResultMatchesClassified.*, ROW_NUMBER()OVER (PARTITION BY source_id, CASE WHEN data_type_id IN (1, 2, 3, 4) THEN \'term\' WHEN data_type_id IN (5, 6) THEN \'reading\' ELSE \'def\' END ORDER BY match_type ASC, LENGTH(text_data) ASC, rank ASC RANGE BETWEEN UNBOUNDED PRECEDING AND CURRENT ROW EXCLUDE NO OTHERS) AS rn FROM SearchResultMatchesClassified) WHERE rn = 1), TermBankMatches AS (SELECT SearchResultsDeduplicated.*, term_bank_v3_table.id AS term_bank_id, term_bank_v3_table.term_id AS term_id, term_bank_v3_table.reading_id AS reading_id, term_bank_v3_table.index_id, 1 AS match_column, term_bank_v3_table.sequence_number, 0 AS def_rank FROM SearchResultsDeduplicated JOIN term_bank_v3_table ON term_bank_v3_table.term_id = source_id AND data_type_id IN (1, 2, 3, 4) JOIN ActiveIndexes ON term_bank_v3_table.index_id = ActiveIndexes.id UNION ALL SELECT SearchResultsDeduplicated.*, term_bank_v3_table.id AS term_bank_id, term_bank_v3_table.term_id AS term_id, term_bank_v3_table.reading_id AS reading_id, term_bank_v3_table.index_id, 2 AS match_column, term_bank_v3_table.sequence_number, 0 AS def_rank FROM SearchResultsDeduplicated JOIN term_bank_v3_table ON term_bank_v3_table.reading_id = source_id AND data_type_id IN (5, 6) JOIN ActiveIndexes ON term_bank_v3_table.index_id = ActiveIndexes.id UNION ALL SELECT SearchResultsDeduplicated.*, term_bank_v3_x_definition_table.term_bank_id AS term_bank_id, term_bank_v3_table.term_id AS term_id, term_bank_v3_table.reading_id AS reading_id, term_bank_v3_table.index_id, 3 AS match_column, term_bank_v3_table.sequence_number, term_bank_v3_x_definition_table.rank AS def_rank FROM SearchResultsDeduplicated JOIN term_bank_v3_x_definition_table ON term_bank_v3_x_definition_table.definition_id = source_id JOIN term_bank_v3_table ON term_bank_v3_table.id = term_bank_v3_x_definition_table.term_bank_id AND data_type_id = 7 JOIN ActiveIndexes ON term_bank_v3_table.index_id = ActiveIndexes.id), TermBankMatchesFiltered AS (SELECT TBM.* FROM TermBankMatches AS TBM WHERE(?5 IS NULL OR EXISTS (SELECT 1 AS _c0 FROM fts_terms WHERE "rowid" = TBM.term_id AND ?4 = 0 AND term MATCH \'"\' || "REPLACE"(?5, \'"\', \'""\') || \'"\' UNION ALL SELECT 1 FROM fts_terms WHERE "rowid" = TBM.term_id AND ?4 = 1 AND fts_terms MATCH \'"\' || "REPLACE"(?5, \'"\', \'""\') || \'"\'))AND(?6 IS NULL OR EXISTS (SELECT 1 AS _c1 FROM fts_readings WHERE "rowid" = TBM.reading_id AND ?4 = 0 AND reading MATCH \'"\' || "REPLACE"(?6, \'"\', \'""\') || \'"\' UNION ALL SELECT 1 FROM fts_readings WHERE "rowid" = TBM.reading_id AND ?4 = 1 AND fts_readings MATCH \'"\' || "REPLACE"(?6, \'"\', \'""\') || \'"\'))AND(?7 IS NULL OR EXISTS (SELECT 1 AS _c2 FROM term_bank_v3_x_definition_table AS link JOIN fts_definitions AS def_fts ON link.definition_id = def_fts."rowid" WHERE link.term_bank_id = TBM.term_bank_id AND def_fts.definition MATCH \'"\' || "REPLACE"(?7, \'"\', \'""\') || \'"\'))AND(TBM.allowed_tags IS NULL OR json_array_length(TBM.allowed_tags) = 0 OR EXISTS (SELECT 1 AS _c3 FROM term_bank_v3_x_tag_bank_table AS LinkTable JOIN tag_bank_v3_table AS TagTable ON LinkTable.tag_bank_id = TagTable.id JOIN json_each(TBM.allowed_tags)AS AllowedTag ON TagTable.name = AllowedTag.value WHERE LinkTable.term_bank_id = TBM.term_bank_id))AND(TBM.allowed_rules IS NULL OR json_array_length(TBM.allowed_rules) = 0 OR EXISTS (SELECT 1 AS _c4 FROM term_bank_v3_x_rule_identifier_table AS RuleLink JOIN term_bank_v3_rule_identifier_table AS RuleTable ON RuleLink.rule_identifier_id = RuleTable.id JOIN json_each(TBM.allowed_rules)AS AllowedRule ON RuleTable.rule_identifier = AllowedRule.value WHERE RuleLink.term_bank_id = TBM.term_bank_id))), FrequencyOverrideIsActive AS (SELECT 1 AS is_active FROM index_table WHERE current_frequency_dictionary = TRUE LIMIT 1), PopularityDictionary AS (SELECT term_meta_bank_v3_table.*, IT.frequency_mode AS op_frequency_mode FROM index_table AS IT JOIN term_meta_bank_v3_table ON term_meta_bank_v3_table.index_id = IT.id JOIN term_meta_bank_v3_type_table ON term_meta_bank_v3_table.type_id = term_meta_bank_v3_type_table.id WHERE IT.current_frequency_dictionary = TRUE AND term_meta_bank_v3_type_table.type = \'freq\') SELECT TBM.term_bank_id, TBM.search_term, TBM.rank AS fts5_rank, TBM.match_type, TBM.match_column, TBM.sequence_number, ActiveIndexes.id AS indexId, ActiveIndexes.current_sorting_order, CASE WHEN FrequencyOverrideIsActive.is_active = 1 THEN CASE WHEN OP.op_frequency_mode = \'rankBased\' THEN(OP.freq_value * -1)ELSE OP.freq_value END ELSE CASE WHEN ActiveIndexes.frequency_mode = \'rankBased\' THEN(TB3T.popularity * -1)ELSE TB3T.popularity END END AS finalPopularity, CASE WHEN TBM.match_column = 1 THEN TT.term WHEN TBM.match_column = 2 THEN RT.reading ELSE TBM.text_data END AS matchedText, LENGTH(CASE WHEN TBM.match_column = 1 THEN TT.term WHEN TBM.match_column = 2 THEN RT.reading ELSE TBM.text_data END) AS matchedTextLength FROM TermBankMatchesFiltered AS TBM JOIN ActiveIndexes ON TB3T.index_id = ActiveIndexes.id JOIN term_bank_v3_table AS TB3T ON TBM.term_bank_id = TB3T.id LEFT JOIN term_table AS TT ON TB3T.term_id = TT.id LEFT JOIN reading_table AS RT ON TB3T.reading_id = RT.id LEFT JOIN FrequencyOverrideIsActive ON 1 = 1 LEFT JOIN PopularityDictionary AS OP ON OP.term_id = TB3T.term_id ORDER BY TBM.input_index ASC, CASE WHEN FrequencyOverrideIsActive.is_active = 1 THEN 0 ELSE ActiveIndexes.current_sorting_order END, TBM.match_type, TBM.match_column, CASE WHEN TBM.match_column = 3 THEN TBM.def_rank ELSE 0 END ASC, finalPopularity DESC, CASE WHEN FrequencyOverrideIsActive.is_active = 1 THEN ActiveIndexes.current_sorting_order ELSE 0 END, TBM.rank, LENGTH(matchedText) ASC, matchedText ASC LIMIT ?8 OFFSET ?9',
      variables: [
        Variable<String>(searchInputs),
        Variable<String>(indexesToInclude),
        Variable<int>(useGlob),
        Variable<int>(normalizedSearch),
        Variable<String>(filterTerm),
        Variable<String>(filterReading),
        Variable<String>(filterDefinition),
        Variable<int>(limit),
        Variable<int>(offset),
      ],
      readsFrom: {
        indexTable,
        termTable,
        ftsTerms,
        ftsTokens,
        readingTable,
        ftsReadings,
        ftsDefinitions,
        definitionTable,
        termBankV3Table,
        termBankV3XDefinitionTable,
        termBankV3XTagBankTable,
        tagBankV3Table,
        termBankV3XRuleIdentifierTable,
        termBankV3RuleIdentifierTable,
        termMetaBankV3Table,
        termMetaBankV3TypeTable,
      },
    ).map(
      (QueryRow row) => DictionarySearchDriftFindTermBankEntriesResult(
        termBankId: row.read<int>('term_bank_id'),
        searchTerm: row.read<String>('search_term'),
        fts5Rank: row.readNullable<double>('fts5_rank'),
        matchType: row.read<int>('match_type'),
        matchColumn: row.read<int>('match_column'),
        sequenceNumber: row.read<int>('sequence_number'),
        indexId: row.read<int>('indexId'),
        currentSortingOrder: row.read<int>('current_sorting_order'),
        finalPopularity: row.readNullable<int>('finalPopularity'),
        matchedText: row.readNullable<String>('matchedText'),
        matchedTextLength: row.read<int>('matchedTextLength'),
      ),
    );
  }

  Selectable<DictionarySearchDriftFindTermBankSequencesByPairsResult>
  dictionary_search_drift_find_term_bank_sequences_by_pairs(
    String lookupPairs,
    String excludedTermBankIds,
  ) {
    return customSelect(
      'WITH RequiredLookups (seqNumber, targetDictId) AS (SELECT CAST(json_extract(value, \'\$.s\') AS INTEGER), CAST(json_extract(value, \'\$.d\') AS INTEGER) FROM json_each(?1)), ExcludedTermBankIds (termBankId) AS (SELECT value FROM json_each(?2)WHERE value IS NOT NULL) SELECT term_bank_v3_table.id AS term_bank_id, term_bank_v3_table.index_id, NULL AS search_term, NULL AS fts5_rank, 4 AS match_type, NULL AS match_column, index_table.current_sorting_order AS current_sorting_order, NULL AS finalPopularity, NULL AS matchedText, NULL AS matchedTextLength, term_bank_v3_table.sequence_number FROM RequiredLookups JOIN term_bank_v3_table ON term_bank_v3_table.sequence_number = RequiredLookups.seqNumber AND term_bank_v3_table.index_id = RequiredLookups.targetDictId JOIN index_table ON term_bank_v3_table.index_id = index_table.id LEFT JOIN ExcludedTermBankIds AS Excluded ON term_bank_v3_table.id = Excluded.termBankId WHERE Excluded.termBankId IS NULL',
      variables: [
        Variable<String>(lookupPairs),
        Variable<String>(excludedTermBankIds),
      ],
      readsFrom: {termBankV3Table, indexTable},
    ).map(
      (QueryRow row) => DictionarySearchDriftFindTermBankSequencesByPairsResult(
        termBankId: row.read<int>('term_bank_id'),
        indexId: row.read<int>('index_id'),
        searchTerm: row.readNullable<String>('search_term'),
        fts5Rank: row.readNullable<String>('fts5_rank'),
        matchType: row.read<int>('match_type'),
        matchColumn: row.readNullable<String>('match_column'),
        currentSortingOrder: row.read<int>('current_sorting_order'),
        finalPopularity: row.readNullable<String>('finalPopularity'),
        matchedText: row.readNullable<String>('matchedText'),
        matchedTextLength: row.readNullable<String>('matchedTextLength'),
        sequenceNumber: row.read<int>('sequence_number'),
      ),
    );
  }

  Selectable<DictionarySearchDriftFindTermBankDetailsResult>
  dictionary_search_drift_find_term_bank_details(String termBankIdJson) {
    return customSelect(
      'WITH TargetIds (term_bank_id) AS (SELECT CAST(value AS INTEGER) FROM json_each(?1)), FrequencyOverrideIsActive AS (SELECT 1 AS is_active FROM index_table WHERE current_frequency_dictionary = TRUE LIMIT 1), PopularityDictionary AS (SELECT term_meta_bank_v3_table.*, IT.frequency_mode AS op_frequency_mode FROM index_table AS IT JOIN term_meta_bank_v3_table ON term_meta_bank_v3_table.index_id = IT.id JOIN term_meta_bank_v3_type_table ON term_meta_bank_v3_table.type_id = term_meta_bank_v3_type_table.id WHERE IT.current_frequency_dictionary = TRUE AND term_meta_bank_v3_type_table.type = \'freq\'), definitions_agg AS (SELECT term_bank_id, JSON_GROUP_ARRAY(definition ORDER BY sort_key)AS definitions FROM term_bank_v3_definitions_json_view WHERE term_bank_id IN (SELECT term_bank_id FROM TargetIds) GROUP BY term_bank_id), def_tags_agg AS (SELECT term_bank_id, JSON_GROUP_ARRAY(JSON(tag_json)) AS definition_tags FROM (SELECT DISTINCT term_bank_id, tag_json FROM term_bank_v3_def_tags_json_view WHERE term_bank_id IN (SELECT term_bank_id FROM TargetIds)) AS DistinctTags GROUP BY term_bank_id), rules_agg AS (SELECT term_bank_id, JSON_GROUP_ARRAY(rule_identifier) AS rule_identifiers FROM (SELECT DISTINCT term_bank_id, rule_identifier FROM term_bank_v3_rules_json_view WHERE term_bank_id IN (SELECT term_bank_id FROM TargetIds)) AS DistinctRules GROUP BY term_bank_id), tags_agg AS (SELECT term_bank_id, JSON_GROUP_ARRAY(JSON(tag_json)) AS tags FROM (SELECT DISTINCT term_bank_id, tag_json FROM term_bank_v3_tags_json_view WHERE term_bank_id IN (SELECT term_bank_id FROM TargetIds)) AS DistinctTags GROUP BY term_bank_id), FilteredMetaBank AS (SELECT Base.*, TBM.term_bank_id FROM term_meta_bank_v3_base_view AS Base JOIN (SELECT DISTINCT id AS term_bank_id, term_id, reading_id FROM term_bank_v3_table WHERE id IN (SELECT term_bank_id FROM TargetIds)) AS TBM ON Base.term_id = TBM.term_id AND(Base.reading_id = TBM.reading_id OR Base.reading_id IS NULL)), term_meta_agg AS (SELECT FMB.term_bank_id, COALESCE(JSON_GROUP_ARRAY(JSON_OBJECT(\'id\', FMB.term_meta_id, \'indexEntry\', FMB.index_entry, \'term\', FMB.term, \'reading\', FMB.reading, \'type\', FMB.type, \'frequency\', FMB.frequency, \'frequencyDisplayValue\', FMB.frequencyDisplayValue, \'pitchs\', CASE WHEN FMB.type = \'pitch\' THEN JSON(COALESCE(ap.pitches, \'[]\')) ELSE JSON(\'[]\') END, \'ipas\', CASE WHEN FMB.type = \'ipa\' THEN JSON(COALESCE(ai.ipas, \'[]\')) ELSE JSON(\'[]\') END))FILTER (WHERE FMB.type IS NOT NULL), JSON(\'[]\')) AS termMetaEntries FROM FilteredMetaBank AS FMB LEFT JOIN term_meta_bank_v3_pitches_json_view AS ap ON FMB.term_meta_id = ap.term_meta_id LEFT JOIN term_meta_bank_v3_ipas_json_view AS ai ON FMB.term_meta_id = ai.term_meta_id WHERE((FMB.type = \'pitch\' AND ap.pitches IS NOT NULL)OR(FMB.type = \'ipa\' AND ai.ipas IS NOT NULL)OR(FMB.type = \'freq\'))GROUP BY FMB.term_bank_id) SELECT index_table.*, COALESCE(FrequencyOverrideIsActive.is_active, 0) AS hasPopularityOverride, OP.freq_value AS overriddenPopularityValue, TB3T.popularity AS originalPopularity, CASE WHEN FrequencyOverrideIsActive.is_active = 1 THEN OP.freq_value ELSE TB3T.popularity END AS finalPopularity, TB3T.id AS term_bank_v3_id, IV.id AS indexId, IV.index_entry AS indexEntry, TT.term, RT.reading, TB3T.popularity, TB3T.sequence_number, TDJT.definition_json AS structuredContentDefinitions, COALESCE(DA.definitions, \'[]\') AS definitions, COALESCE(DTA.definition_tags, \'[]\') AS definition_tags, COALESCE(RA.rule_identifiers, \'[]\') AS rule_identifiers, COALESCE(TA.tags, \'[]\') AS tags, COALESCE(TMA.termMetaEntries, \'[]\') AS termMetaEntries FROM term_bank_v3_table AS TB3T JOIN index_table ON TB3T.index_id = index_table.id JOIN index_entry_as_json_view AS IV ON TB3T.index_id = IV.id LEFT JOIN term_table AS TT ON TB3T.term_id = TT.id LEFT JOIN reading_table AS RT ON TB3T.reading_id = RT.id LEFT JOIN definitions_agg AS DA ON TB3T.id = DA.term_bank_id LEFT JOIN term_bank_v3_definition_json_table AS TDJT ON TB3T.definition_json_id = TDJT.id LEFT JOIN def_tags_agg AS DTA ON TB3T.id = DTA.term_bank_id LEFT JOIN rules_agg AS RA ON TB3T.id = RA.term_bank_id LEFT JOIN tags_agg AS TA ON TB3T.id = TA.term_bank_id LEFT JOIN FrequencyOverrideIsActive ON 1 = 1 LEFT JOIN PopularityDictionary AS OP ON OP.term_id = TB3T.term_id LEFT JOIN term_meta_agg AS TMA ON TB3T.id = TMA.term_bank_id WHERE TB3T.id IN (SELECT term_bank_id FROM TargetIds)',
      variables: [Variable<String>(termBankIdJson)],
      readsFrom: {
        indexTable,
        termMetaBankV3Table,
        termMetaBankV3TypeTable,
        termBankV3Table,
        termTable,
        readingTable,
        termBankV3DefinitionJsonTable,
        termBankV3XDefinitionTable,
        definitionTable,
        termBankV3XDefinitionTagTable,
        tagBankV3Table,
        termBankV3XRuleIdentifierTable,
        termBankV3RuleIdentifierTable,
        termBankV3XTagBankTable,
        termMetaBankV3XPitchTable,
        termMetaBankV3PitchTable,
        termMetaBankV3PitchTableXTagBankV3Table,
        termMetaBankV3XIpaTable,
        termMetaBankV3IpaTable,
        termMetaBankV3IpaTableXTagBankV3Table,
      },
    ).map(
      (QueryRow row) => DictionarySearchDriftFindTermBankDetailsResult(
        id: row.read<int>('id'),
        isDefaultDictionary: row.read<bool>('is_default_dictionary'),
        enabled: row.read<bool>('enabled'),
        dictionaryType: $IndexTableTable.$converterdictionaryType.fromSql(
          row.read<String>('dictionary_type'),
        ),
        currentSortingOrder: row.read<int>('current_sorting_order'),
        currentFrequencyDictionary: row.read<bool>(
          'current_frequency_dictionary',
        ),
        title: row.read<String>('title'),
        revision: row.read<String>('revision'),
        sequenced: row.readNullable<bool>('sequenced'),
        format: row.readNullable<int>('format'),
        version: row.readNullable<int>('version'),
        author: row.readNullable<String>('author'),
        isUpdatable: row.readNullable<bool>('is_updatable'),
        indexUrl: row.readNullable<String>('index_url'),
        downloadUrl: row.readNullable<String>('download_url'),
        url: row.readNullable<String>('url'),
        description: row.readNullable<String>('description'),
        attribution: row.readNullable<String>('attribution'),
        sourceLanguage: row.readNullable<String>('source_language'),
        targetLanguage: row.readNullable<String>('target_language'),
        frequencyMode: NullAwareTypeConverter.wrapFromSql(
          $IndexTableTable.$converterfrequencyMode,
          row.readNullable<String>('frequency_mode'),
        ),
        hasPopularityOverride: row.read<int>('hasPopularityOverride'),
        overriddenPopularityValue: row.readNullable<int>(
          'overriddenPopularityValue',
        ),
        originalPopularity: row.read<int>('originalPopularity'),
        finalPopularity: row.readNullable<int>('finalPopularity'),
        termBankV3Id: row.read<int>('term_bank_v3_id'),
        indexId: row.read<int>('indexId'),
        indexEntry: row.read<String>('indexEntry'),
        term: row.readNullable<String>('term'),
        reading: row.readNullable<String>('reading'),
        popularity: row.read<int>('popularity'),
        sequenceNumber: row.read<int>('sequence_number'),
        structuredContentDefinitions: NullAwareTypeConverter.wrapFromSql(
          $TermBankV3DefinitionJsonTableTable.$converterdefinitionJson,
          row.readNullable<Uint8List>('structuredContentDefinitions'),
        ),
        definitions: row.read<String>('definitions'),
        definitionTags: row.read<String>('definition_tags'),
        ruleIdentifiers: row.read<String>('rule_identifiers'),
        tags: row.read<String>('tags'),
        termMetaEntries: row.read<String>('termMetaEntries'),
      ),
    );
  }

  Selectable<GetMbSizesDriftResult> get_mb_sizes_drift() {
    return customSelect(
      'SELECT name, sum(pgsize) AS bytes, format(\'%.2f MB\', CAST(sum(pgsize) AS REAL) /(1024 * 1024)) AS megabytes FROM dbstat GROUP BY name ORDER BY bytes DESC',
      variables: [],
      readsFrom: {},
    ).map(
      (QueryRow row) => GetMbSizesDriftResult(
        name: row.read<String>('name'),
        bytes: row.readNullable<int>('bytes'),
        megabytes: row.read<String>('megabytes'),
      ),
    );
  }

  Selectable<TermBankV3EntryViewData> term_bank_v3_search_drift(
    String? query,
    int limit,
    int offset,
  ) {
    return customSelect(
      'SELECT * FROM term_bank_v3_entry_view WHERE term = ?1 LIMIT ?2 OFFSET ?3',
      variables: [
        Variable<String>(query),
        Variable<int>(limit),
        Variable<int>(offset),
      ],
      readsFrom: {
        termBankV3XDefinitionTable,
        definitionTable,
        termBankV3XDefinitionTagTable,
        tagBankV3Table,
        indexTable,
        termBankV3XRuleIdentifierTable,
        termBankV3RuleIdentifierTable,
        termBankV3XTagBankTable,
        termBankV3Table,
        termTable,
        readingTable,
        termBankV3DefinitionJsonTable,
      },
    ).asyncMap(termBankV3EntryView.mapFromRow);
  }

  Selectable<TermBankV3EntryViewData> get_term_bank_v3_entries_for_ids(
    List<int> ids,
  ) {
    var $arrayStartIndex = 1;
    final expandedids = $expandVar($arrayStartIndex, ids.length);
    $arrayStartIndex += ids.length;
    return customSelect(
